	private static boolean awaitPendingCount(SketchBasedJoinEstimator estimator, int expected, long timeout,
			TimeUnit unit) throws InterruptedException {
		long deadline = System.nanoTime() + unit.toNanos(timeout);
		while (System.nanoTime() < deadline) {
			if (estimator.debugPendingIncrementalCount() == expected) {
				return true;
			}
			Thread.sleep(10);
		}
		return estimator.debugPendingIncrementalCount() == expected;
	}

